form:Form.form:Scripts:
		function LoadForm()
{
	Ctrl('f_ingreso').SetTypedValue(new Date());
	SetCalendario();	
	SetPuesto();
	SetData();
}

function SetCalendario()
{
	Ctrl('oi_calendario').SetWhere("ORG27_CAL_FERIADOS.oi_calendario IN (SELECT ORG03_FERIADOS_EMP.oi_calendario FROM ORG03_FERIADOS_EMP WHERE ORG03_FERIADOS_EMP.oi_empresa = "+ Ctrl("oi_empresa").GetXValue() + ")");
}

function SetLegajo()
{
	var legajo;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	legajo = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LEGAJO"), "<PARAM oi_empresa=\""+Ctrl("oi_empresa").GetXValue()+"\" />"); 			
	Ctrl("e_numero_legajo").SetXValue(legajo.e_numero_legajo);				
}

function SetPuesto()
{
	var puesto;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	puesto = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PUESTO"), "<PARAM oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 		
	Ctrl("oi_puesto").SetXValue(puesto.oi_puesto);				
}

function SetData()
{
	var reclutado;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	reclutado = nSQL.GetOBJ(Ctrl("main").getResource("QRY_RECLUTADO"), "<PARAM oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 		

	if (reclutado.oi_personal_emp != "0")
	{		
		Ctrl("e_numero_legajo").SetXValue(reclutado.e_numero_legajo);					
		Ctrl("oi_tipo_personal").SetXValue(reclutado.oi_tipo_personal);				
		Ctrl("oi_ctro_costo").SetXValue(reclutado.oi_ctro_costo);				
		Ctrl("oi_calendario").SetXValue(reclutado.oi_calendario);				
		CtrlEnabled("e_numero_legajo", false);
		CtrlEnabled("oi_tipo_personal", false);
		CtrlEnabled("oi_ctro_costo", false);
		CtrlEnabled("oi_calendario", false);
	}
	else if (reclutado.oi_postulante != "0")
	{		
		SetLegajo();
		CtrlEnabled("e_numero_legajo", true);
		CtrlEnabled("oi_tipo_personal", true);
		CtrlEnabled("oi_ctro_costo", true);
		CtrlEnabled("oi_calendario", true);
	}


}
